UPDATE public.questions SET
  stimulus_text = 'The history of the Olympics is one filled with stories of athletic achievements, technological advancements, and political controversies.  It’s important to remember, however, that the games have not always been the symbol of international unity and peace that they are often presented to be.  In the early decades of the 20th century, for example, many of the games were dominated by the political tensions of the day, and some of the most popular and successful athletes were actively involved in promoting the political agendas of their respective countries.',
  question_text = 'Which choice best combines the sentences at the underlined portion to create a grammatically correct and stylistically effective sentence? ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"It’s important to remember, however, that the games have not always been the symbol of international unity and peace that they are often presented to be—in the early decades of the 20th century, for example, many of the games were dominated by the political tensions of the day.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"It’s important to remember, however, that the games have not always been the symbol of international unity and peace that they are often presented to be, for in the early decades of the 20th century, many of the games were dominated by the political tensions of the day.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"It’s important to remember, however, that the games have not always been the symbol of international unity and peace that they are often presented to be, and in the early decades of the 20th century, for example, many of the games were dominated by the political tensions of the day.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"It’s important to remember, however, that the games have not always been the symbol of international unity and peace that they are often presented to be; in the early decades of the 20th century, for example, many of the games were dominated by the political tensions of the day.","is_correct":true,"explanation":"The semicolon correctly joins the two independent clauses, creating a more sophisticated and complex sentence structure than the comma or the coordinating conjunction \"and.\" This semicolon also creates a slight pause, emphasizing the contrast between the idea that the Olympics are often presented as. Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
